function parseRange(s) {
  const m = s.match(/^(-?\d+)-(-?\d+)$/);
  if (m) {
    const a = +m[1];
    const b = +m[2];
    const r = [];
    if (a <= b) {
      for (let i = a; i <= b; i++) r.push(i);
    } else {
      for (let i = a; i >= b; i--) r.push(i);
    }
    return r;
  }
  return [+s];
}
